import { getTokenName, splitModes } from './utils.js';
/**
 * exports js object to be spread into theme.colors.extend (and later replace theme.colors altogether)
 * mirrors the css variable outputs and uses vars as value
 *
 * Example:
 * {
 *    'bg-base': 'var(--bg-base)',
 *    'fg-active': 'var(--fg-active)',
 *    ...
 * }
 */
const formatTwExports = ({ dictionary, options }) => {
    const getExportDeclaration = (varName) => {
        if (options.moduleType === 'esm') {
            return `export const ${varName}`;
        }
        return `module.exports.${varName}`;
    };
    // we only care about the var names and those should all be the same across modes
    const { light: tokens } = splitModes(dictionary.allTokens, ['light']);
    const tokenNames = tokens?.map((token) => getTokenName(token, 'light')) ?? [];
    const tokenLines = tokenNames.map((tokenName) => `  ${tokenName}: 'var(--${tokenName})',`);
    const tokenExportLines = [
        `${getExportDeclaration('tokens')} = {`,
        ...tokenLines,
        '};',
    ];
    const output = [...tokenExportLines, ''].join('\n');
    return output;
};
export const getTwFormatter = (moduleType) => (args) => {
    // args is params obj
    return formatTwExports({ ...args, options: { ...args.options, moduleType } });
};
